script:
frappe.ui.form.on('Collection In Hand', {
    before_save(frm) {
        if (frm.doc.amount > 0) {
            frm.set_value('amount', -Math.abs(frm.doc.amount));
        }
    }
});

frappe.ui.form.on("Loan Group Assignment", {
    onload: function(frm) {
        frm.set_query("loan_group", function() {
            return {
                filters: {
                    workflow_state: "Approved"
                }
            };
        });
    }
});

frappe.ui.form.on('Company', {
    custom_start_sending_messages_before_days(frm) {
        frm.clear_table('custom_message_schedule');
        no_of_days = frm.doc.custom_start_sending_messages_before_days
        console.log(no_of_days ,'....')
        if (no_of_days && no_of_days > 0) {
            for (let i = 1; i <= no_of_days; i++) {
                let row = frm.add_child('custom_message_schedule');
                console.log('row ....',row)
                row.day = i;
            }
        }
        frm.refresh_field('custom_message_schedule');
    }
});
